#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 100005
#define MAXK 27
int N, K, G[MAXK], adj[MAXN][MAXN], visited[MAXN];
void dfs(int u) {
    visited[u] = 1;
    for (int v = 1; v <= N; v++) {
        if (adj[u][v] && !visited[v]) {
            dfs(v);
        }
    }
}
int main() {
    scanf("%d", &N);
    for (int i = 1; i < N; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        adj[u][v] = adj[v][u] = 1;
    }
    scanf("%d", &K);
    for (int i = 0; i < K; i++) {
        scanf("%d", &G[i]);
    }
    int ans = 0;
    for (int mask = 0; mask < (1 << K); mask++) {
        memset(visited, 0, sizeof(visited));
        for (int i = 0; i < K; i++) {
            if ((mask >> i) & 1) {
                dfs(G[i]);
            }
        }
        int cnt = 0;
        for (int u = 1; u <= N; u++) {
            for (int v = 1; v <= N; v++) {
                if (adj[u][v] && !visited[u] && !visited[v]) {
                    cnt++;
                }
            }
        }
        ans ^= cnt;
    }
    printf("%d\n", ans);
    return 0;
}

