        for (int i = 0; i < K; i++) {
            G[i] = sc.nextInt();
        }
        int ans = 0;
        for (int mask = 0; mask < (1 << K); mask++) {
            for (int i = 0; i <= N; i++) {
                visited[i] = 0;
            }
            for (int i = 0; i < K; i++) {
                if ((mask >> i & 1) == 1) {
                    dfs(G[i]);
                }
